"""A readable parser for standard 5-field cron expressions.

A cron expression has five space-separated fields::

    minute  hour  day_of_month  month  day_of_week
      *      *         *          *         *

Each field supports wildcards (``*``), single values (``42``), ranges
(``1-5``), lists (``1,3,5``), and steps (``*/15`` or ``1-30/5``).

The public entry point is :func:`parse_cron`, which returns a
:class:`CronSchedule`.  The schedule exposes the parsed value of every field
plus a :meth:`CronSchedule.describe` method that renders a human-readable
English summary.
"""

from __future__ import annotations

import re
from dataclasses import dataclass


# ---------------------------------------------------------------------------
# Field definitions
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class FieldBounds:
    """The name and inclusive value range allowed for a single cron field."""

    name: str
    minimum: int
    maximum: int


MINUTE = FieldBounds("minute", 0, 59)
HOUR = FieldBounds("hour", 0, 23)
DAY_OF_MONTH = FieldBounds("day of month", 1, 31)
MONTH = FieldBounds("month", 1, 12)
DAY_OF_WEEK = FieldBounds("day of week", 0, 6)

# The five fields, in the order they appear in a cron expression.
FIELD_ORDER: tuple[FieldBounds, ...] = (
    MINUTE,
    HOUR,
    DAY_OF_MONTH,
    MONTH,
    DAY_OF_WEEK,
)

DAY_NAMES: tuple[str, ...] = (
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
)

MONTH_NAMES: tuple[str, ...] = (
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
)


class CronError(ValueError):
    """Raised when a cron expression is malformed or out of range."""


# ---------------------------------------------------------------------------
# Parsing
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class CronField:
    """A single parsed cron field.

    ``raw`` is the original token (used to describe the field's intent), while
    ``values`` is the fully expanded, sorted set of matching integers.
    """

    bounds: FieldBounds
    raw: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        """True for ``*`` — the field matches every value in its range."""
        return self.raw == "*"

    @property
    def is_single_value(self) -> bool:
        """True when the field matches exactly one value (e.g. ``42``)."""
        return len(self.values) == 1

    @property
    def single_value(self) -> int:
        """The sole matching value (only valid when :attr:`is_single_value`)."""
        return self.values[0]

    @property
    def is_full_range_step(self) -> bool:
        """True for ``*/n`` — every nth value across the whole range."""
        return bool(re.fullmatch(r"\*/\d+", self.raw))

    @property
    def is_simple_range(self) -> bool:
        """True for ``a-b`` — a contiguous range with no list or step."""
        return bool(re.fullmatch(r"\d+-\d+", self.raw))

    @property
    def step(self) -> int:
        """The step size if one was given (the ``n`` in ``*/n``), else 1."""
        _, separator, step_text = self.raw.partition("/")
        return int(step_text) if separator else 1


def parse_cron(expression: str) -> "CronSchedule":
    """Parse a 5-field cron ``expression`` into a :class:`CronSchedule`."""
    tokens = split_into_fields(expression)
    fields = tuple(
        parse_field(token, bounds) for token, bounds in zip(tokens, FIELD_ORDER)
    )
    return CronSchedule(*fields)


def split_into_fields(expression: str) -> list[str]:
    """Split an expression into exactly five tokens, or raise CronError."""
    tokens = expression.split()
    if len(tokens) != len(FIELD_ORDER):
        raise CronError(
            f"expected {len(FIELD_ORDER)} fields "
            f"but got {len(tokens)}: {expression!r}"
        )
    return tokens


def parse_field(token: str, bounds: FieldBounds) -> CronField:
    """Parse one field token (which may be a comma-separated list of parts)."""
    matched: set[int] = set()
    for part in token.split(","):
        matched.update(parse_part(part, bounds))
    return CronField(bounds=bounds, raw=token, values=tuple(sorted(matched)))


def parse_part(part: str, bounds: FieldBounds) -> set[int]:
    """Expand a single part (``*``, ``a``, ``a-b``, ``*/n``, ``a-b/n``)."""
    range_text, has_step, step_text = part.partition("/")
    step = parse_step(step_text, bounds) if has_step else 1
    low, high = parse_bounds(range_text, bounds, open_ended=has_step)
    return set(range(low, high + 1, step))


def parse_bounds(
    range_text: str, bounds: FieldBounds, *, open_ended: bool
) -> tuple[int, int]:
    """Resolve the low/high endpoints described by ``range_text``.

    ``open_ended`` is true when a step follows a bare value (e.g. ``5/15``),
    in which case the range runs from the value up to the field's maximum.
    """
    if range_text == "*":
        return bounds.minimum, bounds.maximum

    if "-" in range_text:
        low_text, high_text = range_text.split("-", maxsplit=1)
        return validate(low_text, bounds), validate(high_text, bounds)

    value = validate(range_text, bounds)
    return value, (bounds.maximum if open_ended else value)


def parse_step(step_text: str, bounds: FieldBounds) -> int:
    """Parse and validate the step size in a ``.../n`` expression."""
    if not re.fullmatch(r"\d+", step_text):
        raise CronError(f"invalid {bounds.name} step: {step_text!r}")
    step = int(step_text)
    if step < 1:
        raise CronError(f"{bounds.name} step must be at least 1, got {step}")
    return step


def validate(value_text: str, bounds: FieldBounds) -> int:
    """Parse a single integer and confirm it lies within the field's bounds."""
    if not re.fullmatch(r"\d+", value_text):
        raise CronError(f"invalid {bounds.name} value: {value_text!r}")
    value = int(value_text)
    if not bounds.minimum <= value <= bounds.maximum:
        raise CronError(
            f"{bounds.name} value {value} is outside "
            f"{bounds.minimum}-{bounds.maximum}"
        )
    return value


# ---------------------------------------------------------------------------
# The parsed result
# ---------------------------------------------------------------------------


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression with a human-readable description."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Render the schedule as an English sentence."""
        clauses = [
            describe_time(self.minute, self.hour),
            describe_day_of_week(self.day_of_week),
            describe_calendar(self.day_of_month, self.month),
        ]
        return " ".join(clause for clause in clauses if clause)


# ---------------------------------------------------------------------------
# Description helpers
# ---------------------------------------------------------------------------


def describe_time(minute: CronField, hour: CronField) -> str:
    """Describe the time-of-day portion (minute + hour) of the schedule."""
    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"

    if minute.is_full_range_step and hour.is_wildcard:
        return f"Every {minute.step} minutes"

    if minute.is_single_value and minute.single_value == 0 and hour.is_full_range_step:
        return f"Every {hour.step} hours, on the hour"

    if minute.is_single_value and hour.is_single_value:
        return describe_clock_time(hour.single_value, minute.single_value)

    if minute.is_single_value and hour.is_wildcard:
        return f"At {minute.single_value} minutes past every hour"

    if minute.is_wildcard and hour.is_single_value:
        return f"Every minute of the {hour.single_value:02d}:00 hour"

    return (
        f"At minute(s) {format_number_list(minute.values)} "
        f"past hour(s) {format_number_list(hour.values)}"
    )


def describe_clock_time(hour: int, minute: int) -> str:
    """Describe a single wall-clock time, e.g. ``At 08:30`` or ``At midnight``."""
    if hour == 0 and minute == 0:
        return "At midnight"
    return f"At {hour:02d}:{minute:02d}"


def describe_day_of_week(field: CronField) -> str:
    """Describe the day-of-week constraint, e.g. ``on Monday through Friday``."""
    if field.is_wildcard:
        return ""
    if field.is_simple_range:
        low, high = field.values[0], field.values[-1]
        return f"on {DAY_NAMES[low]} through {DAY_NAMES[high]}"
    names = [DAY_NAMES[value] for value in field.values]
    return "on " + join_with_and(names)


def describe_calendar(day_of_month: CronField, month: CronField) -> str:
    """Describe the day-of-month and month constraints together."""
    if day_of_month.is_wildcard and month.is_wildcard:
        return ""

    if day_of_month.is_wildcard:
        return f"in {describe_months(month)}"

    return f"on the {describe_days(day_of_month)} of {describe_months(month)}"


def describe_days(field: CronField) -> str:
    """Describe a day-of-month constraint as ordinals, e.g. ``1st`` or ``1st and 15th``."""
    ordinals = [ordinal(value) for value in field.values]
    return join_with_and(ordinals)


def describe_months(field: CronField) -> str:
    """Describe a month constraint, e.g. ``every month`` or ``January and July``."""
    if field.is_wildcard:
        return "every month"
    names = [MONTH_NAMES[value - 1] for value in field.values]
    return join_with_and(names)


# ---------------------------------------------------------------------------
# Small formatting utilities
# ---------------------------------------------------------------------------


def join_with_and(items: list[str]) -> str:
    """Join items with commas and a final "and": ``a, b, and c``."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def format_number_list(values: tuple[int, ...]) -> str:
    """Render a tuple of integers as a readable list, e.g. ``5, 10, and 15``."""
    return join_with_and([str(value) for value in values])


def ordinal(number: int) -> str:
    """Return the ordinal form of ``number``, e.g. 1 -> ``1st``, 22 -> ``22nd``."""
    if 10 <= number % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


# ---------------------------------------------------------------------------
# Demo
# ---------------------------------------------------------------------------


if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expression in examples:
        print(f"{expression:<16} -> {parse_cron(expression).describe()}")
```

## Design notes

**Decomposition** follows the natural shape of the problem — three layers, each readable top-to-bottom:

1. **Parse** (`parse_cron` → `split_into_fields` → `parse_field` → `parse_part` → `parse_bounds`/`parse_step`/`validate`). The key reuse point: all five fields run through the *same* `parse_field`/`parse_part` pipeline, parameterized only by a `FieldBounds`. Nothing is duplicated.

2. **Represent** — `CronField` and `CronSchedule` are frozen dataclasses. `CronField` keeps both the expanded `values` (for matching) and the original `raw` token (so descriptions can reflect *intent*, e.g. `*/15` vs. an equivalent literal list). Field "shape" questions live as small, named `@property` predicates (`is_wildcard`, `is_full_range_step`, `is_simple_range`) rather than scattered regex checks.

3. **Describe** — `describe()` composes three independent clause builders (time, day-of-week, calendar) and drops empties. Each builder is short and self-contained; tiny formatting helpers (`join_with_and`, `ordinal`) keep them clean.

**Validation** is centralized in `validate`/`parse_step`, which raise `CronError` with field-named messages like `hour value 25 is outside 0-23`.

**Verified outputs** (all six match exactly):
```
* * * * *        -> Every minute
0 12 * * 1-5     -> At 12:00 on Monday through Friday
*/15 * * * *     -> Every 15 minutes
0 0 1 * *        -> At midnight on the 1st of every month
30 8 * * 1,3,5   -> At 08:30 on Monday, Wednesday, and Friday
0 */2 * * *      -> Every 2 hours, on the hour
```

