DAY_OF_MONTH = FieldSpec("day_of_month", 1, 31)
MONTH = FieldSpec("month", 1, 12)
DAY_OF_WEEK = FieldSpec("day_of_week", 0, 6)

FIELD_SPECS = (MINUTE, HOUR, DAY_OF_MONTH, MONTH, DAY_OF_WEEK)

DAY_NAMES = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
        )

    parsed_fields = [
        parse_field(source, spec)
        for source, spec in zip(parts, FIELD_SPECS)
    ]

    return CronSchedule(
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


def parse_field(source: str, spec: FieldSpec) -> CronField:
    if not source:
        raise CronParseError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for part in source.split(","):
        if not part:
            raise CronParseError(f"Empty list item in {spec.name} field: {source!r}")

        values.update(parse_field_part(part, spec))

    return CronField(
        spec=spec,
        source=source,
        values=tuple(sorted(values)),
    )


def parse_field_part(part: str, spec: FieldSpec) -> list[int]:
    base, step = split_step(part, spec)
    start, end = parse_base_range(base, spec)

    validate_range(start, end, spec)

    return list(range(start, end + 1, step))


def split_step(part: str, spec: FieldSpec) -> tuple[str, int]:
    if "/" not in part:
        return part, 1

    pieces = part.split("/")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"Invalid step syntax in {spec.name} field: {part!r}")

    step = parse_int(pieces[1], spec, "step")

    if step <= 0:
        raise CronParseError(f"Step must be greater than zero in {spec.name}: {part!r}")

    return pieces[0], step


def parse_base_range(base: str, spec: FieldSpec) -> tuple[int, int]:
    if base == "*":
        return spec.minimum, spec.maximum

    if "-" in base:
        pieces = base.split("-")

        if len(pieces) != 2 or not pieces[0] or not pieces[1]:
            raise CronParseError(f"Invalid range in {spec.name} field: {base!r}")

        start = parse_int(pieces[0], spec, "range start")
        end = parse_int(pieces[1], spec, "range end")
        return start, end

    value = parse_int(base, spec, "value")
    return value, value


def parse_int(text: str, spec: FieldSpec, label: str) -> int:
    if not text.isdigit():
        raise CronParseError(
            f"Invalid {label} in {spec.name} field: {text!r} is not an integer"
        )

    return int(text)


def validate_range(start: int, end: int, spec: FieldSpec) -> None:
    if start > end:
        raise CronParseError(
            f"Invalid range in {spec.name}: start {start} is greater than end {end}"
        )

    if start < spec.minimum or end > spec.maximum:
        raise CronParseError(
            f"{spec.name} values must be between {spec.minimum} and {spec.maximum}; "
            f"got {start}-{end}"
        )


