        and schedule.hour.is_wildcard
        and schedule.day_of_month.is_wildcard
        and schedule.month.is_wildcard
        and schedule.day_of_week.is_wildcard
    )


def is_simple_hour_step(schedule: CronSchedule) -> bool:
