    )


def extract_step(source: str) -> int:
    return int(source.split("/", 1)[1])


def describe_time(hour: CronField, minute: CronField) -> str:
    if hour.contains_single_value() and minute.contains_single_value():
        hour_value = hour.single_value()
        minute_value = minute.single_value()

