        return f"At {hour_value:02d}:{minute_value:02d}"

    if minute.contains_single_value():
        return f"At minute {minute.single_value()} past every selected hour"

    if hour.contains_single_value():
        return f"Every selected minute during hour {hour.single_value():02d}"

    return "At every selected minute of every selected hour"


def describe_date(
    day_of_month: CronField,
